import React from "react";
import ReactECharts from "echarts-for-react";

const Dashboard = () => {
  function run() {
    const categories = ["Category A", "Category B", "Category C"];

    // Prepare dataset
    const datasetWithFilters = [];
    const seriesList = [];

    echarts.util.each(categories, function (category, index) {
      var datasetId = "dataset_" + category;

      datasetWithFilters.push({
        id: datasetId,
        fromDatasetId: "dataset_raw",
        transform: {
          type: "filter",
          config: {
            and: [{ dimension: "Category", "===": category }],
          },
        },
      });

      seriesList.push({
        type: "line",
        datasetId: datasetId,
        showSymbol: false,
        name: category,
        endLabel: {
          show: true,
          formatter: function (params) {
            return params.value[1] + ": " + params.value[0];
          },
        },
        labelLayout: {
          moveOverlap: "shiftY",
        },
        emphasis: {
          focus: "series",
        },
        encode: {
          x: "Month",
          y: "Value",
          label: ["Category", "Value"],
          itemName: "Month",
          tooltip: ["Value"],
        },
      });
    });

    // ECharts options
    const option = {
      animationDuration: 10000,
      dataset: [
        {
          id: "dataset_raw",
          source: [
            { Month: "Jan", Category: "Category A", Value: 10 },
            { Month: "Feb", Category: "Category A", Value: 20 },
            { Month: "Mar", Category: "Category A", Value: 30 },
            { Month: "Apr", Category: "Category A", Value: 40 },
            { Month: "May", Category: "Category A", Value: 50 },
            { Month: "Jun", Category: "Category A", Value: 60 },
            { Month: "Jul", Category: "Category A", Value: 70 },
            { Month: "Jan", Category: "Category B", Value: 15 },
            { Month: "Feb", Category: "Category B", Value: 25 },
            { Month: "Mar", Category: "Category B", Value: 35 },
            { Month: "Apr", Category: "Category B", Value: 45 },
            { Month: "May", Category: "Category B", Value: 55 },
            { Month: "Jun", Category: "Category B", Value: 65 },
            { Month: "Jul", Category: "Category B", Value: 75 },
            { Month: "Jan", Category: "Category C", Value: 5 },
            { Month: "Feb", Category: "Category C", Value: 15 },
            { Month: "Mar", Category: "Category C", Value: 25 },
            { Month: "Apr", Category: "Category C", Value: 35 },
            { Month: "May", Category: "Category C", Value: 45 },
            { Month: "Jun", Category: "Category C", Value: 55 },
            { Month: "Jul", Category: "Category C", Value: 65 },
          ],
        },
        ...datasetWithFilters,
      ],
      title: { text: "Line Race Animation Chart" },
      tooltip: { trigger: "axis", order: "valueDesc" },
      xAxis: { type: "category", name: "Month" },
      yAxis: { name: "Value" },
      grid: { right: 140 },
      series: seriesList,
    };

    // Initialize ECharts
    const chart = echarts.init(document.getElementById("chart-container"));
    chart.setOption(option);

    // Line race animation
    let index = 0;
    const updateInterval = setInterval(() => {
      if (index >= 20) {
        clearInterval(updateInterval);
        return;
      }

      // Update values slightly to create movement
      option.dataset[0].source.forEach((row) => {
        row.Value += Math.round(Math.random() * 10 - 5); // Random variation
      });

      chart.setOption({ dataset: option.dataset });

      index++;
    }, 1000);
  }

  run();

  const lineRaceOptions = {
    title: {
      text: "Line Race Chart",
    },
    tooltip: {
      trigger: "axis",
    },
    legend: {
      data: ["Category A", "Category B", "Category C"],
    },
    xAxis: {
      type: "category",
      data: ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul"],
    },
    yAxis: {
      type: "value",
    },
    series: [
      {
        name: "Category A",
        type: "line",
        data: [10, 20, 30, 40, 50, 60, 70],
        smooth: true,
      },
      {
        name: "Category B",
        type: "line",
        data: [15, 25, 35, 45, 55, 65, 75],
        smooth: true,
      },
      {
        name: "Category C",
        type: "line",
        data: [5, 15, 25, 35, 45, 55, 65],
        smooth: true,
      },
    ],
  };

  const chartOptions = {
    title: {
      text: "Sales Over Time",
    },
    tooltip: {},
    legend: {
      data: ["Sales Line", "Sales Bar"],
    },
    xAxis: {
      type: "category",
      data: ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul"],
    },
    yAxis: [
      {
        type: "value",
        name: "Sales",
      },
      {
        type: "value",
        name: "Other Metric",
        position: "right",
        offset: 0,
      },
    ],
    series: [
      {
        name: "Sales Line",
        type: "line",
        data: [30, 40, 35, 50, 49, 60, 70],
      },
      {
        name: "Sales Bar",
        type: "bar",
        data: [20, 30, 25, 40, 35, 50, 60],
        yAxisIndex: 1,
      },
    ],
  };

  const barChartOptions = {
    title: {
      text: "Sales by Month",
    },
    tooltip: {},
    xAxis: {
      type: "category",
      data: ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul"],
    },
    yAxis: {
      type: "value",
    },
    series: [
      {
        name: "Sales",
        type: "bar",
        data: [20, 30, 25, 40, 35, 50, 60],
      },
    ],
  };

  const pieChartOptions = {
    title: {
      text: "Inspection Types",
    },
    tooltip: {},
    series: [
      {
        name: "Types",
        type: "pie",
        data: [
          { value: 30, name: "Inspections" },
          { value: 40, name: "Follow-ups" },
          { value: 30, name: "Re-inspections" },
        ],
      },
    ],
  };

  return (
    <div>
      <h1>Dashboard</h1>
      <div className="kpis">
        <div className="kpi">
          <h2>Total Sales</h2>
          <p>$100,000</p>
        </div>
        <div className="kpi">
          <h2>Total Inspections</h2>
          <p>250</p>
        </div>
        <div className="kpi">
          <h2>Active Users</h2>
          <p>150</p>
        </div>
      </div>
      <ReactECharts option={lineRaceOptions} />
      <ReactECharts option={chartOptions} />
      <ReactECharts option={barChartOptions} />
      <ReactECharts option={pieChartOptions} />
    </div>
  );
};

export default Dashboard;
